prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?start ?startName ?task ?taskName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo ;
         bbo:name ?startName .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  FILTER NOT EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?start ?startName ?reachableCount WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo ;
         bbo:name ?startName .

  {
    SELECT (COUNT(DISTINCT ?task) AS ?reachableCount) WHERE {
      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
      ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo .
    }
  }
}
ORDER BY DESC(?reachableCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?normId ?origId ?startType ?startName ?taskCount WHERE {
  VALUES ?id { "1ad939eef40c461dafae27f75a0586d3" }
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:normalizedId ?normId .
  OPTIONAL { ?model tai:originalId ?origId . }
  FILTER( ?normId = ?id || ?origId = ?id )

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  ?start a ?startType ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  {
    SELECT (COUNT(DISTINCT ?task) AS ?taskCount) WHERE {
      ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo .
    }
  }
}
ORDER BY ?startType
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?start ?startName ?next ?nextName WHERE {
  VALUES ?normId { "1ad939eef40c461dafae27f75a0586d3" }
  ?model a bboExt:Model ;
         tai:normalizedId ?normId .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo ;
         bbo:name ?startName .

  ?edge a bbo:SequenceFlow ;
        bbo:has_sourceRef ?start ;
        bbo:has_targetRef ?next .

  ?next a ?nextType .
  OPTIONAL { ?next bbo:name ?nextName . }
}
LIMIT 25
